const now = new Date();
const month = (now.getMonth() + 1).toString().padStart(2, '0');
const year = now.getFullYear();
const month_year = `${month}-${year}`;
return [{json: {month_year}}];

// Employee data aur attendance data merge ho chuka hai
const employee = $input.item.json;
const attendance = $input.all()[1]?.json || {};

// Basic calculation
const dailySalary = employee.basic_salary / 30;
const absentDeduction = (attendance.absent_days || 0) * dailySalary;
const lateDeduction = (attendance.late_days || 0) * 500;

// Gross aur Net Salary
const grossSalary = employee.basic_salary + (employee.allowance || 0);
const totalDeductions = Math.round(absentDeduction + lateDeduction);
const netSalary = grossSalary - totalDeductions;

// Month year ko properly fetch karna
const monthYear = $node["CD - Calculate Month/Year"].json.month_year;

return {
  json: {
    employee_id: employee.id,
    employee_name: employee.name,
    employee_email: employee.email,
    employee_phone: employee.phone,
    basic_salary: employee.basic_salary,
    allowance: employee.allowance || 0,
    working_days: attendance.working_days || 30,
    present_days: attendance.present_days || 0,
    absent_days: attendance.absent_days || 0,
    late_days: attendance.late_days || 0,
    daily_salary: Math.round(dailySalary),
    absent_deduction: Math.round(absentDeduction),
    late_deduction: lateDeduction,
    gross_salary: grossSalary,
    total_deductions: totalDeductions,
    net_salary: netSalary,
    payslip_date: new Date().toISOString().split('T')[0],
    month_year: monthYear
  }
};

